// Validar e extrair payload
const body = $input.first().json.body || $input.first().json;

// Campos obrigatórios raiz
const rootRequired = ['request_id', 'organizacao_id', 'actor_user_id'];
for (const f of rootRequired) {
  if (!body[f]) throw new Error(`Campo obrigatório ausente: ${f}`);
}

const data = body.data || {};

// Apenas blocos_ids é realmente obrigatório
if (!Array.isArray(data.blocos_ids) || data.blocos_ids.length === 0) {
  throw new Error('blocos_ids deve ser array não vazio');
}

return [{ json: {
  request_id:          body.request_id,
  organizacao_id:      body.organizacao_id,
  actor_user_id:       body.actor_user_id,
  historico_id:        body.historico_id || null,
  processo_id:         data.processo_id        || null,
  modelo_id:           data.modelo_id          || null,
  versao_id:           data.versao_id          || null,
  advogado_id:         data.advogado_id        || null,
  tipo_peticao_id:     data.tipo_peticao_id    || null,
  blocos_ids:          data.blocos_ids,
  jurisprudencias_ids: Array.isArray(data.jurisprudencias_ids) ? data.jurisprudencias_ids : [],
  instrucoes_finais:   data.instrucoes_finais  || ''
}}];

// B3-BuscarJuris — busca jurisprudências se IDs presentes
const validado = $('A1-Validate').first().json;
const ids = validado.jurisprudencias_ids || [];

if (ids.length === 0) {
  return [{ json: { jurisprudencias: [] } }];
}

const SK = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFkaXZmYWlyeGhkaWhhcXF5cGdiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MTA3MzcwOCwiZXhwIjoyMDg2NjQ5NzA4fQ.zu_reCiKzCqLETOWxytYQmez1SIwFRDlOruzsLOpBeY';
const SUPA = 'https://qdivfairxhdihaqqypgb.supabase.co';

try {
  const idsStr = ids.join(',');
  const url = `${SUPA}/rest/v1/olivia_jurisprudencias?id=in.(${idsStr})&select=id,titulo,ementa,google_doc_id&limit=20`;
  const resp = await fetch(url, {
    headers: { 'apikey': SK, 'Authorization': 'Bearer ' + SK, 'Accept': 'application/json' }
  });
  if (!resp.ok) {
    console.error('[B3] Erro ao buscar jurisprudências:', resp.status);
    return [{ json: { jurisprudencias: [] } }];
  }
  const rows = await resp.json();
  const juris = (Array.isArray(rows) ? rows : []).map(j => ({
    id: j.id,
    titulo: j.titulo || '',
    ementa: j.ementa || '',
    google_doc_id: j.google_doc_id || null
  }));
  console.log('[B3] Jurisprudências encontradas:', juris.length);
  return [{ json: { jurisprudencias: juris } }];
} catch(e) {
  console.error('[B3] Exceção:', e.message);
  return [{ json: { jurisprudencias: [] } }];
}

// C1-MontarPayloadJARBAS v5.0
// Monta payload para JARBAS /olivia/criar-doc
// JARBAS recebe: titulo_documento, google_folder_id, peticao_html (modelo HTML), 
//               modelo.google_doc_id (template Google Doc), blocos[].google_doc_id,
//               secoes (alias para blocos), tags (substituições)

const validado   = ($('A1c-MergeHistorico').first() || $('A1-Validate').first() || {json:{}}).json;
const _proc = ($('B1-BuscarProcesso').first() || {json:[]}).json; const processo = (Array.isArray(_proc) ? (_proc[0] || {}) : _proc) || {};
const _adv = ($('B1b-BuscarAdvogado').first() || {json:[]}).json; const advogado = (Array.isArray(_adv) ? (_adv[0] || {}) : _adv) || {};
const _cli = ($('B1c-BuscarCliente').first() || {json:[]}).json; const cliente = (Array.isArray(_cli) ? (_cli[0] || {}) : _cli) || {};
const _emp = ($('B1d-BuscarEmpresa').first() || {json:[]}).json; const empresa = (Array.isArray(_emp) ? (_emp[0] || {}) : _emp) || {};
const _mdl = ($('B1e-BuscarModelo').first() || {json:[]}).json; const modeloRow = (Array.isArray(_mdl) ? (_mdl[0] || {}) : _mdl) || {};
const blocosData = ($('B2b-AgregaBlocos').first() || {json:{blocos:[]}}).json.blocos || [];
const jurisData  = $('B3-BuscarJuris').first().json.jurisprudencias || [];

// Mapa de blocos preservando ordem do frontend
const blocoMap = {};
for (const b of blocosData) blocoMap[b.id] = b;

const blocos = validado.blocos_ids
  .map((id, idx) => {
    const b = blocoMap[id];
    if (!b || !b.google_doc_id) return null;
    return { ordem: idx + 1, placeholder: `{{bloco_${idx + 1}}}`, google_doc_id: b.google_doc_id };
  })
  .filter(Boolean);

if (blocos.length === 0) {
  // Nenhum bloco com google_doc_id — salvar erro no historico e abortar graciosamente
  const historico_id_err = validado.historico_id;
  if (historico_id_err) {
    const SK = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFkaXZmYWlyeGhkaWhhcXF5cGdiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MTA3MzcwOCwiZXhwIjoyMDg2NjQ5NzA4fQ.zu_reCiKzCqLETOWxytYQmez1SIwFRDlOruzsLOpBeY';
    await fetch(`https://qdivfairxhdihaqqypgb.supabase.co/rest/v1/olivia_historico?id=eq.${historico_id_err}`, {
      method: 'PATCH',
      headers: { 'apikey': SK, 'Authorization': 'Bearer ' + SK, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify({ status: 'ERRO', error_message: 'Nenhum bloco com google_doc_id encontrado. Configure os blocos com documento Google no Playbooks.', finished_at: new Date().toISOString() })
    });
  }
  throw new Error('Nenhum bloco com google_doc_id encontrado');
}

// secoes = blocos (compatibilidade com GAS/JARBAS v4.2+)
const secoes = blocos.map(b => ({
  ordem: b.ordem,
  tipo: 'bloco',
  google_doc_id: b.google_doc_id,
  placeholder: b.placeholder
}));

const jurisprudencias = jurisData
  .map((j, idx) => (j.google_doc_id ? { placeholder: `{{jurisprudencia_${idx + 1}}}`, google_doc_id: j.google_doc_id, titulo: j.titulo || '' } : null))
  .filter(Boolean);

const modeloGoogleDocId = modeloRow.google_doc_id_origem || null;
// conteudo_template do modelo (HTML) — usado como peticao_html base pelo JARBAS
const conteudoTemplate = modeloRow.conteudo_template || '';

// Dados advogado
const metaAdv = advogado.meta || {};
const fonteLetra = metaAdv.fonte_letra || 'Arial';
const dadosBancarios = metaAdv.dados_bancarios || '';
const advCidade = metaAdv.cidade || 'Canoas';
const advRodape = advogado.cabecalho_escritorio || '';

const oabCodigo = advogado.oab || '';
const oabNumero = advogado.oab_uf
  ? oabCodigo.replace(new RegExp('^' + advogado.oab_uf), '').trim()
  : oabCodigo;
const oabFormatado = advogado.oab_uf
  ? `OAB/${advogado.oab_uf} ${oabNumero}`
  : `OAB/${oabCodigo}`;

const sexo = cliente.sexo || '';
const isMasc = sexo === 'Masculino' || sexo === 'M';
const qualificacaoSexo    = isMasc ? 'já qualificado'  : 'já qualificada';
const sexoNacionalidade   = isMasc ? 'brasileiro'      : 'brasileira';
const sexoInscrito        = isMasc ? 'inscrito'        : 'inscrita';
const sexoPortador        = isMasc ? 'portador'        : 'portadora';
const sexoDomiciliado     = isMasc ? 'domiciliado'     : 'domiciliada';

const clienteEndereco = [
  cliente.endereco_logradouro || '',
  cliente.endereco_numero ? `nº ${cliente.endereco_numero}` : '',
  [cliente.cidade, cliente.endereco_uf].filter(Boolean).join('/'),
  cliente.cep ? `CEP ${cliente.cep}` : ''
].filter(Boolean).join(', ');

const mapaEstados = { RS: 'Rio Grande do Sul', SP: 'São Paulo', SC: 'Santa Catarina', PR: 'Paraná', MG: 'Minas Gerais', RJ: 'Rio de Janeiro' };
const uf = (cliente.endereco_uf || processo.estado_id || '').toUpperCase();
const estadoExtenso = mapaEstados[uf] || uf;

const dataHoje = new Date().toLocaleDateString('pt-BR', { day: 'numeric', month: 'long', year: 'numeric', timeZone: 'America/Sao_Paulo' });
const dataRestricao = processo.restricao_data ? new Date(processo.restricao_data + 'T12:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: '2-digit' }) : '';

const restricaoValorNum = parseFloat(String(processo.restricao_valor || 0));
const valorCausaNum = 15000 + restricaoValorNum;
const valorCausaFmt = valorCausaNum.toLocaleString('pt-BR', { minimumFractionDigits: 2 });
const restricaoValorFmt = restricaoValorNum.toLocaleString('pt-BR', { minimumFractionDigits: 2 });

const enderecamentoJson = processo.enderecamento || {};
const enderecamentoVara = enderecamentoJson.vara_civel || '';

// campos_substituicao — compatível com GAS e JARBAS (JARBAS também aceita como 'tags')
const camposSubstituicao = {
  '{{advogado_nome}}':               (advogado.nome || '').toUpperCase(),
  '{{advogado_oab_codigo}}':         oabCodigo,
  '{{advogado_oab}}':                oabFormatado,
  '{{advogado_enderecamento}}':      advogado.cabecalho_escritorio || '',
  '{{advogado_rodape}}':             advRodape,
  '{{advogado_email}}':              advogado.email || '',
  '{{advogado_cidade}}':             advCidade,
  '{{dados_bancarios}}':             dadosBancarios,
  '{{parte_autora}}':                (cliente.nome || '').toUpperCase(),
  '{{cliente_nome}}':                cliente.nome  || '',
  '{{empresa_re}}':                  processo.reu_nome || empresa.nome || '',
  '{{reu_nome}}':                    processo.reu_nome || empresa.nome || '',
  '{{numero_processo}}':             processo.numero_cnj || processo.numero_processo || '',
  '{{numero_cnj}}':                  processo.numero_cnj || '',
  '{{valor_restricao}}':             restricaoValorFmt,
  '{{contrato_restricao}}':          processo.restricao_contrato || '',
  '{{orgao_restritivo}}':            processo.restricao_orgao_nome || '',
  '{{data_restricao}}':              dataRestricao,
  '{{cliente_cpf}}':                 cliente.cpf_cnpj || '',
  '{{cliente_rg}}':                  cliente.rg       || '',
  '{{cliente_email}}':               cliente.email    || '',
  '{{cliente_profissao}}':           cliente.profissao || '',
  '{{cliente_endereco}}':            clienteEndereco,
  '{{qualificacao_sexo}}':           qualificacaoSexo,
  '{{cliente_sexo_nacionalidade}}':  sexoNacionalidade,
  '{{cliente_sexo_inscrito}}':       sexoInscrito,
  '{{cliente_sexo_portador}}':       sexoPortador,
  '{{cliente_sexo_domiciliado}}':    sexoDomiciliado,
  '{{data_hoje}}':                   dataHoje,
  '{{estado_extenso}}':              estadoExtenso,
  '{{valor_causa}}':                 valorCausaFmt,
  '{{empresa_endereco}}':            '',
  '{{categoria_empresa}}':           '',
  '{{enderecamento_vara}}':          enderecamentoVara,
  '{{cabecalho_escritorio}}':        advogado.cabecalho_escritorio || '',
};

const nomeArquivo = `Petição - ${processo.numero_cnj || ''} - ${cliente.nome || ''}`.trim();

// JARBAS payload — usa conteudo_template como peticao_html base
// e insere blocos via google_doc_id
const gasPayload = {
  titulo_documento: nomeArquivo,
  google_folder_id: '1JTbKJqbmPzRTLlqRYZEZ5pNY-w8r1ALZ',
  // peticao_html: conteudo_template do modelo (JARBAS usa como template base)
  peticao_html: conteudoTemplate || '<p>Petição gerada via Smart Blocks</p>',
  // modelo: referência ao Google Doc do template (JARBAS pode substituir conteúdo)
  modelo: modeloGoogleDocId ? { google_doc_id: modeloGoogleDocId } : null,
  // blocos: cada smart block com seu google_doc_id
  blocos,
  secoes,
  jurisprudencias,
  // tags = campos_substituicao (JARBAS usa 'tags' internamente)
  tags: camposSubstituicao,
  campos_substituicao: camposSubstituicao,
  configuracoes: {
    nome_arquivo: nomeArquivo,
    google_folder_id: '1JTbKJqbmPzRTLlqRYZEZ5pNY-w8r1ALZ',
    fallback_to_root: true,
    debug: false
  },
  config: {
    fonte:                  fonteLetra,
    tamanho_corpo:          12,
    cabecalho_escritorio:   advogado.cabecalho_escritorio || '',
    aplicar_fonte_global:   true
  }
};

return [{ json: {
  historico_id:   validado.historico_id,
  organizacao_id: validado.organizacao_id,
  gasPayload,
  debug: {
    blocos_count:       blocos.length,
    secoes_count:       secoes.length,
    juris_count:        jurisprudencias.length,
    modelo_google_doc:  modeloGoogleDocId,
    conteudo_template_len: conteudoTemplate.length,
    advogado_nome:      advogado.nome,
    cliente_nome:       cliente.nome,
    processo_cnj:       processo.numero_cnj
  }
}}];

// Error handler global — atualiza olivia_historico com status ERRO
const errData = $input.first().json;
const lastError = errData.error || {};
const nodeName = lastError.node?.name || 'desconhecido';
const errorMsg = lastError.message || 'Erro desconhecido';

let historico_id = null;
try { historico_id = $('A1-Validate').first().json.historico_id; } catch(e) {}

if (historico_id) {
  const url = 'https://qdivfairxhdihaqqypgb.supabase.co/rest/v1/olivia_historico?id=eq.' + historico_id;
  const body = JSON.stringify({ status: 'ERRO', error_message: '[' + nodeName + ']: ' + errorMsg, finished_at: new Date().toISOString() });
  try {
    const res = await fetch(url, {
      method: 'PATCH',
      headers: {
        'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFkaXZmYWlyeGhkaWhhcXF5cGdiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MTA3MzcwOCwiZXhwIjoyMDg2NjQ5NzA4fQ.zu_reCiKzCqLETOWxytYQmez1SIwFRDlOruzsLOpBeY',
        'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFkaXZmYWlyeGhkaWhhcXF5cGdiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MTA3MzcwOCwiZXhwIjoyMDg2NjQ5NzA4fQ.zu_reCiKzCqLETOWxytYQmez1SIwFRDlOruzsLOpBeY',
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body
    });
    console.log('[E1] PATCH historico', historico_id, 'HTTP:', res.status);
  } catch(e2) {
    console.error('[E1] Falha fetch:', e2.message);
  }
}

return [{ json: { ok: false, error: errorMsg, node: nodeName, historico_id } }];

// Agrega todos os blocos num único item
const blocos = $input.all().map(i => i.json);
return [{ json: { blocos } }];

// B1-BuscarProcesso: busca dados do processo se processo_id estiver presente
// Input vem de A-Respond202 que herda todos os campos do A1-Validate
const validado = $input.first().json;
const processo_id = validado.processo_id || null;

// Se não tem processo_id, retorna objeto vazio sem erro
if (!processo_id) {
  return [{ json: {} }];
}

const SK = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFkaXZmYWlyeGhkaWhhcXF5cGdiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MTA3MzcwOCwiZXhwIjoyMDg2NjQ5NzA4fQ.zu_reCiKzCqLETOWxytYQmez1SIwFRDlOruzsLOpBeY';
const SUPA = 'https://qdivfairxhdihaqqypgb.supabase.co';

const fields = 'id,numero_processo,numero_cnj,organizacao_id,cliente_id,empresa_id,advogado_id,estado_id,reu_nome,restricao_valor,restricao_data,restricao_contrato,restricao_orgao_nome,enderecamento';
const url = `${SUPA}/rest/v1/processos?id=eq.${processo_id}&select=${fields}&limit=1`;

try {
  const resp = await fetch(url, {
    headers: {
      'apikey': SK,
      'Authorization': 'Bearer ' + SK,
      'Accept': 'application/json'
    }
  });

  if (!resp.ok) {
    return [{ json: {} }];
  }

  const data = await resp.json();
  return [{ json: Array.isArray(data) && data.length > 0 ? data[0] : {} }];
} catch(e) {
  return [{ json: {} }];
}

// A1b-CriarHistorico: reutiliza historico_id se veio no payload
const validado = $('A1-Validate').first().json;

if (validado.historico_id) {
  return [{ json: { id: validado.historico_id, _skipped: true } }];
}

const SK = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFkaXZmYWlyeGhkaWhhcXF5cGdiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MTA3MzcwOCwiZXhwIjoyMDg2NjQ5NzA4fQ.zu_reCiKzCqLETOWxytYQmez1SIwFRDlOruzsLOpBeY';
const SUPA = 'https://qdivfairxhdihaqqypgb.supabase.co';
const resp = await fetch(SUPA + '/rest/v1/olivia_historico', {
  method: 'POST',
  headers: { 'apikey': SK, 'Authorization': 'Bearer ' + SK, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
  body: JSON.stringify({ organizacao_id: validado.organizacao_id, processo_id: validado.processo_id || null, modo: 'SMART_BLOCKS', status: 'PENDENTE', request_id: validado.request_id, motor: 'smart-blocks' }),
});
const data = await resp.json();
const row = Array.isArray(data) ? data[0] : data;
return [{ json: { id: row && row.id ? row.id : null } }];

// Merge historico_id from POST response into A1 validated data
const validado = $('A1-Validate').first().json;

// A1b POST returns the created row (or error body)
const postResult = $input.first().json;
// If it's an array (Supabase returns representation), get first element
const row = Array.isArray(postResult) ? postResult[0] : postResult;
const historico_id = validado.historico_id || row?.id || null;

if (historico_id) {
  console.log('[A1c] historico_id: ' + historico_id);
} else {
  console.log('[A1c] WARNING: historico_id still null. POST response: ' + JSON.stringify(postResult).substring(0,200));
}

return [{ json: {
  ...validado,
  historico_id
}}];
